import{_ as e,o as a,c as r,a2 as l}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 領主忠誠與叛變預防：穩住你的權力基礎","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/lord-loyalty.md","filePath":"bannerlord/lord-loyalty.md"}'),d={name:"bannerlord/lord-loyalty.md"};function i(n,t,o,h,s,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="騎砍2-領主忠誠與叛變預防-穩住你的權力基礎" tabindex="-1">騎砍2 | 領主忠誠與叛變預防：穩住你的權力基礎 <a class="header-anchor" href="#騎砍2-領主忠誠與叛變預防-穩住你的權力基礎" aria-label="Permalink to &quot;騎砍2 | 領主忠誠與叛變預防：穩住你的權力基礎&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>領主叛變是王國崩塌的第一大原因。你辛苦打下十座城，三個領主帶著封地跑掉，瞬間回到解放前。這篇教你怎麼避免。</p><hr><h2 id="一、為什麼領主會叛變" tabindex="-1">一、為什麼領主會叛變 <a class="header-anchor" href="#一、為什麼領主會叛變" aria-label="Permalink to &quot;一、為什麼領主會叛變&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原因</th><th style="text-align:center;">嚴重度</th></tr></thead><tbody><tr><td>沒有封地或封地太少</td><td style="text-align:center;">🔴 最高</td></tr><tr><td>關係值過低</td><td style="text-align:center;">🔴 高</td></tr><tr><td>你一直否決他的提案</td><td style="text-align:center;">🟡 中</td></tr><tr><td>你的王國戰敗連連</td><td style="text-align:center;">🟡 中</td></tr><tr><td>有其他國王挖角他</td><td style="text-align:center;">🟡 中</td></tr><tr><td>文化不同（他帝國人你庫塞特）</td><td style="text-align:center;">🟢 低</td></tr></tbody></table><hr><h2 id="二、關係值管理" tabindex="-1">二、關係值管理 <a class="header-anchor" href="#二、關係值管理" aria-label="Permalink to &quot;二、關係值管理&quot;">​</a></h2><h3 id="_2-1-加關係的方法" tabindex="-1">2.1 加關係的方法 <a class="header-anchor" href="#_2-1-加關係的方法" aria-label="Permalink to &quot;2.1 加關係的方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th style="text-align:center;">效果量</th></tr></thead><tbody><tr><td>分封地給他們</td><td style="text-align:center;">+++++</td></tr><tr><td>支持他們的政策提案</td><td style="text-align:center;">+++</td></tr><tr><td>一起打仗</td><td style="text-align:center;">++</td></tr><tr><td>投票時支持他們</td><td style="text-align:center;">+</td></tr><tr><td>舉辦宴會（需要特定條件）</td><td style="text-align:center;">+</td></tr></tbody></table><h3 id="_2-2-扣關係的行為" tabindex="-1">2.2 扣關係的行為 <a class="header-anchor" href="#_2-2-扣關係的行為" aria-label="Permalink to &quot;2.2 扣關係的行為&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行為</th><th style="text-align:center;">效果量</th></tr></thead><tbody><tr><td>把別人提名給他的封地搶走</td><td style="text-align:center;">-----</td></tr><tr><td>否決他的政策提案</td><td style="text-align:center;">---</td></tr><tr><td>投票反對他</td><td style="text-align:center;">--</td></tr><tr><td>燒他原本所屬國的村莊</td><td style="text-align:center;">-</td></tr></tbody></table><hr><h2 id="三、封地策略" tabindex="-1">三、封地策略 <a class="header-anchor" href="#三、封地策略" aria-label="Permalink to &quot;三、封地策略&quot;">​</a></h2><h3 id="_3-1-黃金比例" tabindex="-1">3.1 黃金比例 <a class="header-anchor" href="#_3-1-黃金比例" aria-label="Permalink to &quot;3.1 黃金比例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>領主類型</th><th style="text-align:center;">建議封地數</th></tr></thead><tbody><tr><td>剛挖來的</td><td style="text-align:center;">1 座（立刻給）</td></tr><tr><td>核心支持者</td><td style="text-align:center;">2-3 座</td></tr><tr><td>一般領主</td><td style="text-align:center;">1-2 座</td></tr><tr><td>國王自己</td><td style="text-align:center;">2-3 座（首都+經濟城）</td></tr></tbody></table><blockquote><p>單一領主超過 3 座城就很危險，他會覺得自己比你強。</p></blockquote><h3 id="_3-2-分配節奏" tabindex="-1">3.2 分配節奏 <a class="header-anchor" href="#_3-2-分配節奏" aria-label="Permalink to &quot;3.2 分配節奏&quot;">​</a></h3><p>不要一次給完。每打下一兩座城給一個領主，讓他們有「跟著國王有好處」的預期。</p><hr><h2 id="四、預防挖角" tabindex="-1">四、預防挖角 <a class="header-anchor" href="#四、預防挖角" aria-label="Permalink to &quot;四、預防挖角&quot;">​</a></h2><p>其他國王會挖你的領主，尤其是：</p><ul><li>文化跟對方國王相同的領主</li><li>沒封地或封地少的領主</li><li>對你不滿的領主</li></ul><h3 id="防挖角對策" tabindex="-1">防挖角對策 <a class="header-anchor" href="#防挖角對策" aria-label="Permalink to &quot;防挖角對策&quot;">​</a></h3><ol><li>確保每個領主都有封地（最基本）</li><li>關係值維持正數</li><li>不讓領主跟敵國領主有太多接觸（別派去邊境）</li><li>裝 Diplomacy MOD → 可以看領主被挖角的風險</li></ol><hr><h2 id="五、叛變後的處理" tabindex="-1">五、叛變後的處理 <a class="header-anchor" href="#五、叛變後的處理" aria-label="Permalink to &quot;五、叛變後的處理&quot;">​</a></h2><p>萬一還是叛變了：</p><h3 id="_5-1-立即行動" tabindex="-1">5.1 立即行動 <a class="header-anchor" href="#_5-1-立即行動" aria-label="Permalink to &quot;5.1 立即行動&quot;">​</a></h3><ol><li>叛變領主帶著你的封地加入敵國</li><li><strong>那塊封地現在是敵國領土</strong></li><li>立刻宣戰敵國 → 把那座城打回來</li><li>俘虜叛變領主 → 處決或永久監禁</li></ol><h3 id="_5-2-殺一儆百" tabindex="-1">5.2 殺一儆百？ <a class="header-anchor" href="#_5-2-殺一儆百" aria-label="Permalink to &quot;5.2 殺一儆百？&quot;">​</a></h3><p>處決叛變領主有威懾效果，但也會大幅扣你跟所有領主的關係。除非他有太多封地造成巨大損失，否則不建議處決。</p><hr><h2 id="六、穩定王國的長遠策略" tabindex="-1">六、穩定王國的長遠策略 <a class="header-anchor" href="#六、穩定王國的長遠策略" aria-label="Permalink to &quot;六、穩定王國的長遠策略&quot;">​</a></h2><ol><li><strong>文化統一</strong>：優先挖角跟你同文化的領主</li><li><strong>封地不要一次給太多</strong>：讓他們一直有追求</li><li><strong>戰事順利</strong>：一直打勝仗的國王不會有人叛變</li><li><strong>政策保護</strong>：元老院政策 + 皇室衛隊</li></ol><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./kingdom-management.html">騎砍2 | 王國管理深度指南</a></li><li><a href="./diplomacy-guide.html">騎砍2 | 外交系統詳解</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',44)])])}const x=e(d,[["render",i]]);export{u as __pageData,x as default};
